use std::collections::BTreeMap;
use std::fmt::Write as _;

use saphyr::YamlOwned;

const BASE: &str = "\
# Generated by pithos — do not edit
# Base stage: Debian bookworm-slim with Node, Python, uv, Pi CLI, and common dev tools pre-installed.
FROM ghcr.io/anton-kochev/pithos:base AS base
USER root
";

/// Emit a Dockerfile for the given parsed `.pithos` config.
///
/// **Precondition:** `yaml` must be the validated output of
/// [`crate::config::load`]. This function trusts that validation has
/// already confirmed the top-level `toolchains` mapping exists and all
/// name/version scalars are well-formed strings; it will panic otherwise.
pub fn emit(yaml: &YamlOwned) -> String {
    let mut out = String::with_capacity(BASE.len() + 128);
    out.push_str(BASE);
    let toolchains = sorted_toolchains(yaml);
    if !toolchains.is_empty() {
        writeln!(out).unwrap();
        writeln!(
            out,
            "# Toolchain: installed via repo-local script, version pinned from .pithos. Alphabetical order keeps layer cache stable across re-renders."
        )
        .unwrap();
        for (i, (name, version)) in toolchains.iter().enumerate() {
            if i > 0 {
                writeln!(out).unwrap();
            }
            writeln!(
                out,
                "COPY toolchains/{name}-install.sh /usr/local/bin/{name}-install.sh"
            )
            .unwrap();
            writeln!(out, "RUN /usr/local/bin/{name}-install.sh {version}").unwrap();
        }
    }
    let packages = apt_packages(yaml);
    if !packages.is_empty() {
        writeln!(out).unwrap();
        writeln!(
            out,
            "# Extras: apt packages from .pithos. Installed after toolchains so editing the package list does not invalidate toolchain layers."
        )
        .unwrap();
        writeln!(
            out,
            "RUN apt-get update && apt-get install -y --no-install-recommends {} && rm -rf /var/lib/apt/lists/*",
            packages.join(" ")
        )
        .unwrap();
    }
    if let Some(version) = pi_version(yaml) {
        writeln!(out).unwrap();
        writeln!(
            out,
            "# Pi: pinned version from .pithos overrides the base image's floor. Ownership is reset so the pi user can read the install tree."
        )
        .unwrap();
        writeln!(
            out,
            "RUN npm install --prefix=/opt/pi-npm -g @earendil-works/pi-coding-agent@{version} && chown -R pi:pi /opt/pi-npm"
        )
        .unwrap();
    }
    writeln!(out).unwrap();
    writeln!(
        out,
        "# Pi-config defaults baked into /opt/pi-defaults/; entrypoint seeds them into the user's volume on first run. Tini handles PID 1 signal forwarding."
    )
    .unwrap();
    writeln!(out, "COPY pi-config/ /opt/pi-defaults/").unwrap();
    writeln!(out, "COPY entrypoint.sh /usr/local/bin/entrypoint.sh").unwrap();
    writeln!(out, "USER pi").unwrap();
    writeln!(
        out,
        "ENTRYPOINT [\"/usr/bin/tini\", \"--\", \"/usr/local/bin/entrypoint.sh\"]"
    )
    .unwrap();
    writeln!(out, "CMD [\"pi\"]").unwrap();
    out
}

fn sorted_toolchains(yaml: &YamlOwned) -> BTreeMap<String, String> {
    // BTreeMap yields sort-by-key for free — determinism is structural.
    // All .expect() calls document the validation contract.
    let mapping = yaml.as_mapping().expect("validated by config::load");
    let mut toolchains: Option<&YamlOwned> = None;
    for (key, value) in mapping {
        let name = key.as_str().expect("validated by config::load");
        if name == "toolchains" {
            toolchains = Some(value);
            break;
        }
    }
    let toolchains = toolchains.expect("validated by config::load");
    let toolchains_map = toolchains.as_mapping().expect("validated by config::load");
    toolchains_map
        .iter()
        .map(|(k, v)| {
            let name = k.as_str().expect("validated by config::load");
            let version = v.as_str().expect("validated by config::load");
            (name.to_string(), version.to_string())
        })
        .collect()
}

/// Return the toolchain names from a validated `.pithos` config in
/// alphabetical order. Used by main.rs to assemble the installer-bytes
/// map for fingerprinting; the full `(name, version)` shape stays private
/// to the emitter.
///
/// **Precondition:** `yaml` must be the validated output of
/// [`crate::config::load`]. Same panic contract as [`emit`].
pub fn toolchain_names(yaml: &YamlOwned) -> impl Iterator<Item = String> {
    sorted_toolchains(yaml).into_keys()
}

fn apt_packages(yaml: &YamlOwned) -> Vec<String> {
    // Walk the top-level mapping for `extras`; absent or null → empty.
    // Then walk the extras mapping for `apt`; absent or null → empty.
    // Order is preserved from user input (apt ordering is user-visible).
    let mapping = yaml.as_mapping().expect("validated by config::load");
    let mut extras: Option<&YamlOwned> = None;
    for (key, value) in mapping {
        let name = key.as_str().expect("validated by config::load");
        if name == "extras" {
            extras = Some(value);
            break;
        }
    }
    let Some(extras) = extras else {
        return Vec::new();
    };
    if extras.is_null() {
        return Vec::new();
    }
    let extras_map = extras.as_mapping().expect("validated by config::load");
    let mut apt: Option<&YamlOwned> = None;
    for (key, value) in extras_map {
        let name = key.as_str().expect("validated by config::load");
        if name == "apt" {
            apt = Some(value);
            break;
        }
    }
    let Some(apt) = apt else {
        return Vec::new();
    };
    if apt.is_null() {
        return Vec::new();
    }
    let seq = apt.as_sequence().expect("validated by config::load");
    seq.iter()
        .map(|item| {
            item.as_str()
                .expect("validated by config::load")
                .to_string()
        })
        .collect()
}

pub fn apt_package_count(yaml: &YamlOwned) -> usize {
    apt_packages(yaml).len()
}

fn pi_version(yaml: &YamlOwned) -> Option<&str> {
    // Mirrors apt_packages: walk top-level for `pi`, then `pi` for `version`.
    // Absent or null → None; validation guarantees the value is a string when present.
    let mapping = yaml.as_mapping().expect("validated by config::load");
    let mut pi: Option<&YamlOwned> = None;
    for (key, value) in mapping {
        let name = key.as_str().expect("validated by config::load");
        if name == "pi" {
            pi = Some(value);
            break;
        }
    }
    let pi = pi?;
    let pi_map = pi.as_mapping().expect("validated by config::load");
    for (key, value) in pi_map {
        let name = key.as_str().expect("validated by config::load");
        if name == "version" {
            return Some(value.as_str().expect("validated by config::load"));
        }
    }
    None
}

